INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0001','en','Standard Tomato Seedling','standard-tomato-seedling','<p>Standard (non-grafted) tomato seedlings produced to Bereket Fide quality standards. Suitable for open-field and greenhouse cultivation, with strong root systems and early harvest potential.</p>','Standard Tomato Seedling — Bereket Fide','[\"tomato\", \"seedling\", \"non-grafted\", \"standard\"]','{\"type\": \"Non-grafted / Standard\", \"yield\": \"High\", \"category\": \"Tomato\", \"production\": \"Open field & Greenhouse\"}','Standard Tomato Seedling | Bereket Fide','High-yield, disease-resistant standard tomato seedlings. Assured by Bereket Fide.','2026-04-13 23:18:21.539','2026-04-16 04:55:14.669');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0001','tr','Düz Domates Fidesi','duz-domates-fidesi','<p>Bereket Fide kalite standartlarında üretilen, yüksek verimli aşısız düz domates fidesi. Açık tarla ve sera yetiştiriciliğine uygun, güçlü kök yapısına sahip, erken hasat imkanı sunan çeşitlerden üretilmektedir.</p>','Aşısız Düz Domates Fidesi — Bereket Fide','[\"domates\", \"fide\", \"aşısız\", \"düz domates\"]','{\"tip\": \"Aşısız / Düz\", \"verim\": \"Yüksek\", \"üretim\": \"Açık tarla & Sera\", \"kategori\": \"Domates\"}','Aşısız Düz Domates Fidesi | Bereket Fide','Yüksek verimli, hastalıklara dayanıklı aşısız düz domates fideleri. Bereket Fide güvencesiyle.','2026-04-13 23:18:21.539','2026-04-16 04:54:49.823');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0002','en','Grafted Tomato Seedling','grafted-tomato-seedling','<p>Grafted tomato seedlings on special rootstocks, fully resistant to soil-borne diseases with maximized fruit quality. Provides high yield throughout the long production season with strong root structure for stress resilience.</p>','Grafted Tomato Seedling — Bereket Fide','[\"grafted\", \"tomato\", \"high yield\", \"resistant\"]','{\"type\": \"Grafted\", \"category\": \"Tomato\", \"rootstock\": \"Special selection\", \"resistance\": \"Maximum\"}','Grafted Tomato Seedling | Bereket Fide','Soil-borne disease resistant, long-season high-quality grafted tomato seedlings.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0002','tr','Aşılı Domates Fidesi','asili-domates-fidesi','<p>Özel anaçlar üzerine aşılanmış, toprak kökenli hastalıklara karşı tam dayanıklı ve meyve kalitesi maksimize edilmiş aşılı domates fidesi. Uzun üretim sezonu boyunca yüksek verim sağlar, kök yapısı güçlü olduğundan stres koşullarına karşı dayanıklıdır.</p>','Aşılı Domates Fidesi — Bereket Fide','[\"aşılı\", \"domates\", \"yüksek verim\", \"dayanıklı\"]','{\"tip\": \"Aşılı\", \"anaç\": \"Özel seleksiyon\", \"kategori\": \"Domates\", \"dayanıklılık\": \"Maksimum\"}','Aşılı Domates Fidesi | Bereket Fide','Toprak kökenli hastalıklara dayanıklı, uzun sezon yüksek kaliteli aşılı domates fideleri.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0003','en','Pepper Seedling','pepper-seedling','<p>Pepper seedlings offering the best yield in sweet, hot, bell, and long pepper varieties. Suitable for greenhouse and open-field conditions, standing out with strong plant structure and high fruit quality.</p>','Pepper Seedling — Bereket Fide','[\"pepper\", \"seedling\", \"sweet pepper\", \"hot pepper\", \"bell pepper\"]','{\"type\": \"Various\", \"category\": \"Pepper\", \"varieties\": \"Sweet, Hot, Bell, Long\"}','Pepper Seedling | Bereket Fide','Quality and productive pepper seedlings. Sweet, hot, bell and long pepper varieties.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0003','tr','Biber Fidesi','biber-fidesi','<p>Tatlı, acı, dolmalık ve sivri biber çeşitlerinde en iyi verimi sunan biber fideleri. Sera ve açık tarla koşullarına uygun, güçlü bitki yapısı ve yüksek meyve kalitesi ile öne çıkar.</p>','Biber Fidesi — Bereket Fide','[\"biber\", \"fide\", \"tatlı biber\", \"acı biber\", \"dolmalık\"]','{\"tip\": \"Çeşitli\", \"kategori\": \"Biber\", \"çeşitler\": \"Tatlı, Acı, Dolmalık, Sivri\"}','Biber Fidesi | Bereket Fide','Kaliteli ve verimli biber fideleri. Tatlı, acı, dolmalık ve sivri biber çeşitleri.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0004','en','Grafted Eggplant Seedling','grafted-eggplant-seedling','<p>Eggplant seedlings grafted onto strong rootstocks provide superior resistance to soil-borne diseases. Ideal for longer harvest periods and higher yields.</p>','Grafted Pepper Seedling — Bereket Fide','[\"grafted\", \"pepper\", \"resistant\", \"high yield\"]','{\"type\": \"Grafted\", \"category\": \"Pepper\", \"resistance\": \"High\"}','Grafted Pepper Seedling | Bereket Fide','Soil-disease resistant, high-yield grafted pepper seedlings.','2026-04-13 23:18:21.539','2026-04-16 04:57:43.770');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0004','tr','Aşılı Patlıcan Fidesi','asili-patlican-fidesi','<p>Güçlü anaçlar üzerine aşılanan patlıcan fideleri, toprak kaynaklı hastalıklara karşı üstün dayanıklılık sağlar. Daha uzun hasat dönemi ve daha yüksek verim için idealdir.</p>','Aşılı Biber Fidesi — Bereket Fide','[\"aşılı\", \"biber\", \"dayanıklı\", \"yüksek verim\"]','{\"tip\": \"Aşılı\", \"kategori\": \"Biber\", \"dayanıklılık\": \"Yüksek\"}','Aşılı Biber Fidesi | Bereket Fide','Toprak hastalıklarına dayanıklı, yüksek verimli aşılı biber fideleri.','2026-04-13 23:18:21.539','2026-04-16 04:56:59.848');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0006','en','Snack Cucumber Seedling','snack-cucumber-seedling','<p>Snack cucumber seedlings suitable for greenhouse and open-field conditions. With thin skin, crispy and flavorful fruit structure, ideal for fresh consumption. Offers early harvest and high yield potential.</p>','Snack Cucumber Seedling — Bereket Fide','[\"snack cucumber\", \"seedling\", \"greenhouse\", \"table\"]','{\"type\": \"Standard\", \"usage\": \"Fresh consumption\", \"category\": \"Snack Cucumber\", \"cultivation\": \"Greenhouse & Open field\"}','Snack Cucumber Seedling | Bereket Fide','High-yield snack cucumber seedlings for greenhouse and open field. Assured by Bereket Fide.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0006','tr','Hıyar Fidesi','hiyar-fidesi','<p>Sera ve açık tarla koşullarına uygun hıyar fideleri. İnce kabuklu, çıtır ve lezzetli meyve yapısıyla sofralık tüketime idealdir. Erken hasat imkanı ve yüksek verim potansiyeli sunar.</p>','Hıyar Fidesi — Bereket Fide','[\"hıyar\", \"fide\", \"sera\", \"sofralık\"]','{\"tip\": \"Normal\", \"kategori\": \"Hıyar\", \"kullanım\": \"Sofralık\", \"yetiştiriclik\": \"Sera & Açık tarla\"}','Hıyar Fidesi | Bereket Fide','Sera ve açık tarla için uygun, yüksek verimli hıyar fideleri. Bereket Fide güvencesiyle.','2026-04-13 23:18:21.539','2026-04-16 04:54:14.265');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0007','en','Melon Seedling','melon-seedling','<p>Melon seedlings produced from aromatic and sweet melon varieties. Distinguished by strong root structure, early maturation and high sugar content. Best suited for open-field cultivation.</p>','Melon Seedling — Bereket Fide','[\"melon\", \"seedling\", \"sweet melon\", \"open field\"]','{\"type\": \"Standard\", \"flavor\": \"High sugar content\", \"category\": \"Melon\", \"cultivation\": \"Open field\"}','Melon Seedling | Bereket Fide','Aromatic, sweet and high-yield melon seedlings. Bereket Fide quality assured.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0007','tr','Kavun Fidesi','kavun-fidesi','<p>Aromatik ve tatlı kavun çeşitlerinden üretilen kavun fideleri. Güçlü kök yapısı, erken olgunlaşma ve yüksek şeker oranı ile öne çıkar. Açık tarla yetiştiriciliğine en uygun fide çeşitleri.</p>','Kavun Fidesi — Bereket Fide','[\"kavun\", \"fide\", \"tatlı kavun\", \"açık tarla\"]','{\"tip\": \"Normal\", \"lezzet\": \"Yüksek şeker oranı\", \"kategori\": \"Kavun\", \"yetiştiriclik\": \"Açık tarla\"}','Kavun Fidesi | Bereket Fide','Aromatik, tatlı ve yüksek verimli kavun fideleri. Bereket Fide kalitesiyle.','2026-04-13 23:18:21.539','2026-04-16 04:51:54.042');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0008','en','Grafted Watermelon Seedling','grafted-watermelon-seedling','<p>Watermelon seedlings grafted onto special squash rootstocks provide full resistance to fusarium wilt and soil-borne diseases. Offers large fruit size, high sugar content and long shelf life. Ideal for professional greenhouse and open-field growers.</p>','Grafted Watermelon Seedling — Bereket Fide','[\"grafted\", \"watermelon\", \"resistant\", \"large fruit\", \"fusarium\"]','{\"type\": \"Grafted\", \"category\": \"Watermelon\", \"rootstock\": \"Squash rootstock\", \"resistance\": \"Fusarium & Soil diseases\"}','Grafted Watermelon Seedling | Bereket Fide','Fusarium and soil-disease resistant, large-fruited grafted watermelon seedlings.','2026-04-13 23:18:21.539','2026-04-13 23:18:21.539');
INSERT IGNORE INTO `product_i18n` (`product_id`, `locale`, `title`, `slug`, `description`, `alt`, `tags`, `specifications`, `meta_title`, `meta_description`, `created_at`, `updated_at`) VALUES ('bf-prd-0008','tr','Aşılı Karpuz Fidesi','asili-karpuz-fidesi','<p>Özel kabak anaçları üzerine aşılanan karpuz fideleri, fusarium solgunluğuna ve toprak kökenli hastalıklara karşı tam dayanıklılık sağlar. Büyük meyve boyutu, yüksek şeker oranı ve uzun raf ömrü sunar. Profesyonel sera ve açık tarla üreticileri için idealdir.</p>','Aşılı Karpuz Fidesi — Bereket Fide','[\"aşılı\", \"karpuz\", \"dayanıklı\", \"büyük meyve\", \"fusarium\"]','{\"tip\": \"Aşılı\", \"anaç\": \"Kabak anacı\", \"kategori\": \"Karpuz\", \"dayanıklılık\": \"Fusarium & Toprak hastalıkları\"}','Aşılı Karpuz Fidesi | Bereket Fide','Fusarium ve toprak hastalıklarına dayanıklı, büyük meyveli aşılı karpuz fideleri.','2026-04-13 23:18:21.539','2026-04-16 04:49:11.057');
